import { toServerItemLeaderboardDetails, } from '../../../models/server/items/leaderboards/details.js';
import { handleError } from '../../error.js';
export const createServerItemLeaderboardDetailsRouteHandler = (sonolus, group) => async ({ req, res, localize, ctx }) => {
    if (!group.leaderboard.detailsHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const leaderboardName = req.params.leaderboardName;
    if (!leaderboardName) {
        res.status(400).end();
        return;
    }
    const response = await group.leaderboard.detailsHandler({
        ...ctx,
        itemName,
        leaderboardName,
    });
    if (handleError(response, res, localize))
        return;
    res.json(toServerItemLeaderboardDetails(sonolus, localize, response));
};
